      "path": "src/app.js",
      "content": "const express = require('express');
const crypto = require('crypto');

const app = express();
app.use(express.json());

// In-memory repositories
const projectsRepo = {};
const membersRepo = {};
const tasksRepo = {};
const commentsRepo = {};

// Health endpoint
app.get('/health', (req, res) => {
  res.status(200).json({ ok: true });
});

// Projects endpoints
require('./modules/projects')(app, projectsRepo, membersRepo, tasksRepo);

// Members endpoints
require('./modules/members')(app, projectsRepo, membersRepo);

// Tasks endpoints
require('./modules/tasks')(app, projectsRepo, tasksRepo, commentsRepo);

// Comments endpoints
require('./modules/comments')(app, tasksRepo, commentsRepo);

module.exports = { app };
"
