    {
      "path": "src/modules/projects/index.js",
      "content": "module.exports = (app, projectsRepo) => {
  // Get all projects
  app.get('/projects', (req, res) => {
    const projects = Object.values(projectsRepo);
    res.status(200).json({ projects });
  });

  // Create a new project
  app.post('/projects', (req, res) => {
    const { name } = req.body;
    if (!name) return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Name is required' } });

    if (Object.values(projectsRepo).some(p => p.name === name)) {
      return res.status(409).json({ error: { code: 'DUPLICATE_PROJECT', message: 'Project with this name already exists' } });
    }

    const projectId = crypto.randomUUID();
    projectsRepo[projectId] = { id: projectId, name };
    res.status(201).json({ project: projectsRepo[projectId] });
  });

  // Get a specific project
  app.get('/projects/:projectId', (req, res) => {
    const { projectId } = req.params;
    if (!projectsRepo[projectId]) return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });

    res.status(200).json({ project: projectsRepo[projectId] });
  });
};
"
    },
    {
      "path": "src/modules/members/index.js",
      "content": "module.exports = (app, projectsRepo, membersRepo) => {
  // Add a member to a project
  app.post('/projects/:projectId/members', (req, res) => {
    const { projectId } = req.params;
    const { userId, role } = req.body;

    if (!userId || !role) return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'UserId and role are required' } });
    if (!projectsRepo[projectId]) return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });

    const memberKey = `${projectId}-${userId}`;
    if (membersRepo[memberKey]) {
      return res.status(409).json({ error: { code: 'DUPLICATE_MEMBER', message: 'Member already exists in this project' } });
    }

    membersRepo[memberKey] = { projectId, userId, role };
    res.status(201).json({ member: membersRepo[memberKey] });
  });
};
"
    },
    {
      "path": "src/modules/tasks/index.js",
      "content": "module.exports = (app, projectsRepo, tasksRepo) => {
  // Get all tasks for a project
  app.get('/projects/:projectId/tasks', (req, res) => {
    const { projectId } = req.params;
    if (!projectsRepo[projectId]) return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });

    const tasks = Object.values(tasksRepo).filter(task => task.projectId === projectId);
    res.status(200).json({ tasks });
  });

  // Create a new task for a project
  app.post('/projects/:projectId/tasks', (req, res) => {
    const { projectId } = req.params;
    const { title } = req.body;

    if (!title) return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Title is required' } });
    if (!projectsRepo[projectId]) return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });

    const taskId = crypto.randomUUID();
    tasksRepo[taskId] = { id: taskId, projectId, title, status: 'pending' };
    res.status(201).json({ task: tasksRepo[taskId] });
  });

  // Update a task's status
  app.patch('/projects/:projectId/tasks/:taskId', (req, res) => {
    const { projectId, taskId } = req.params;
    const { status } = req.body;

    if (!status) return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Status is required' } });
    if (!projectsRepo[projectId]) return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });
    if (!tasksRepo[taskId] || tasksRepo[taskId].projectId !== projectId) {
      return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found in this project' } });
    }

    tasksRepo[taskId].status = status;
    res.status(200).json({ task: tasksRepo[taskId] });
  });
};
"
